{
  "current_stable_level": "string (IL|IM1|IM2|IM3|IH|AL)",
  "ceiling_candidate_level": "string|null",
  "next_step_level": "string",
  "stable_confidence": "number 0~1",
  "floor_status": {
    "intermediate_floor_met": "boolean",
    "ih_floor_met": "boolean",
    "al_floor_met": "boolean"
  },
  "target_gap_summary": {
    "current_to_next": "string (Korean)",
    "next_to_final": "string (Korean)"
  },
  "diagnosis_summary_internal": {
    "level_rationale": ["string"],
    "type_mastery": {"answer_type": "stable|borderline|weak|not_ready"},
    "topic_mastery": {"topic_name": "stable|borderline|weak|not_ready"},
    "type_details": {
      "answer_type_key": {
        "mastery": "stable|borderline|weak|not_ready",
        "reason": "string (Korean, 1-2 sentences: why this status)",
        "evidence": ["string (Korean, specific question evidence, 1-3 items)"]
      }
    },
    "topic_details": {
      "topic_name_key": {
        "mastery": "stable|borderline|weak|not_ready",
        "reason": "string (Korean, 1-2 sentences: why this topic has this status)",
        "evidence": ["string (Korean, specific question evidence, 1-3 items)"]
      }
    }
  },
  "top_bottlenecks_internal": [{
    "bottleneck_code": "string",
    "label": "string (Korean)",
    "category": "foundation|type|skill|target_gap",
    "severity": "number 0~1",
    "recurrence": "number 0~1",
    "source_types": ["string"],
    "source_topics": ["string"],
    "why_it_blocks_target": "string (Korean)"
  }],
  "student_top_focuses": [{
    "focus_code": "string",
    "label": "string (Korean)",
    "reason_summary": "string (Korean)",
    "success_hint": "string (Korean)"
  }],
  "student_summary": {
    "current_level_message": "string (Korean)",
    "next_step_message": "string (Korean)",
    "why_now_message": "string (Korean)"
  }
}

{
  "drill_code": "string",
  "focus_code": "string",
  "session_goal": "string (한국어)",
  "why_this_matters_for_target": "string (한국어)",
  "q1": {
    "question_id": "string",
    "question_english": "string",
    "topic": "string",
    "goal": "string (한국어)",
    "hint_level": "full",
    "frame_slots": [{"slot": "string", "frame_en": "string", "label_ko": "string"}],
    "sample_answer": "string (영어, next_step_level 수준)",
    "pass_criteria": {
      "required_flags": ["string"],
      "min_word_count": "number",
      "min_duration_sec": "number"
    }
  },
  "q2": { "hint_level": "reduced", "...": "q1과 동일 구조" },
  "q3": { "hint_level": "minimal", "rule_only_hint": "string (한국어 1줄)", "...": "q1과 동일 구조" }
}
